// MARK: - Biometric Authentication Manager

final class BiometricAuthManager {
    
    enum BiometricType {
        case none
        case touchID
        case faceID
        case opticID
    }
    
    enum AuthenticationResult {
        case success(sessionToken: String)
        case failure(error: AuthError)
    }
    
    enum AuthError: Error, LocalizedError {
        case biometryNotAvailable
        case biometryNotEnrolled
        case biometryLockout
        case userCancel
        case userFallback
        case systemCancel
        case noSessionStored
        case keychainError(Error)
        case unknown(Error)
        
        var errorDescription: String? {
            switch self {
            case .biometryNotAvailable:
                return "Biometric authentication is not available on this device."
            case .biometryNotEnrolled:
                return "No biometric data is enrolled. Please set up Face ID or Touch ID in Settings."
            case .biometryLockout:
                return "Biometric authentication is locked due to too many failed attempts. Please use your passcode."
            case .userCancel:
                return "Authentication was cancelled."
            case .userFallback:
                return "User chose to enter password."
            case .systemCancel:
                return "Authentication was cancelled by the system."
            case .noSessionStored:
                return "No saved session found. Please log in with your credentials."
            case .keychainError(let error):
                return "Secure storage error: \(error.localizedDescription)"
            case .unknown(let error):
                return "Authentication failed: \(error.localizedDescription)"
            }
        }
    }
    
    static let shared = BiometricAuthManager()
    private let keychainManager = KeychainManager.shared
    
    private init() {}
    
    // MARK: - Biometric Type Detection
    
    var availableBiometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        switch context.biometryType {
        case .touchID:
            return .touchID
        case .faceID:
            return .faceID
        case .opticID:
            return .opticID
        case .none:
            return .none
        @unknown default:
            return .none
        }
    }
    
    var biometricDisplayName: String {
        switch availableBiometricType {
        case .faceID: return "Face ID"
        case .touchID: return "Touch ID"
        case .opticID: return "Optic ID"
        case .none: return "Biometrics"
        }
    }
    
    var biometricIconName: String {
        switch availableBiometricType {
        case .faceID: return "faceid"
        case .touchID: return "touchid"
        case .opticID: return "opticid"
        case .none: return "lock.shield"
        }
    }
    
    var isBiometricAvailable: Bool {
        return availableBiometricType != .none
    }
    
    var hasSavedBiometricSession: Bool {
        return keychainManager.hasBiometricProtectedSession()
    }
    
    // MARK: - Enable Biometric Login (called after successful password login)
    
    func enableBiometricLogin(withSessionToken token: String, completion: @escaping (Result<Void, AuthError>) -> Void) {
        guard isBiometricAvailable else {
            completion(.failure(.biometryNotAvailable))
            return
        }
        
        do {
            try keychainManager.storeSessionTokenWithBiometricProtection(token)
            try keychainManager.storeSessionToken(token)
            completion(.success(()))
        } catch {
            completion(.failure(.keychainError(error)))
        }
    }
    
    // MARK: - Authenticate with Biometrics (retrieves session token from keychain)
    
    func authenticateWithBiometrics(reason: String? = nil, completion: @escaping (AuthenticationResult) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Use Password"
        context.localizedFallbackTitle = "Enter Password"
        
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            let authError = mapLAError(error)
            completion(.failure(authError))
            return
        }
        
        guard hasSavedBiometricSession else {
            completion(.failure(.noSessionStored))
            return
        }
        
        let authReason = reason ?? "Authenticate with \(biometricDisplayName) to access your account"
        
        // The keychain access itself triggers biometric authentication
        // We use LAContext to pre-authenticate, then pass it to keychain
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: authReason) { [weak self] success, evaluationError in
            guard let self = self else { return }
            
            DispatchQueue.main.async {
                if success {
                    // Now retrieve the token using the authenticated context
                    do {
                        let token = try self.keychainManager.retrieveSessionTokenWithBiometric(
                            context: context,
                            reason: authReason
                        )
                        completion(.success(sessionToken: token))
                    } catch {
                        completion(.failure(.keychainError(error)))
                    }
                } else if let error = evaluationError {
                    let authError = self.mapLAError(error as NSError?)
                    completion(.failure(authError))
                } else {
                    completion(.failure(.unknown(NSError(domain: "BiometricAuth", code: -1))))
                }
            }
        }
    }
    
    // MARK: - Disable Biometric Login
    
    func disableBiometricLogin() {
        keychainManager.clearBiometricSession()
    }
    
    func clearAllAuthData() {
        keychainManager.clearAllSessions()
    }
    
    // MARK: - Error Mapping
    
    private func mapLAError(_ error: NSError?) -> AuthError {
        guard let error = error else { return .unknown(NSError(domain: "BiometricAuth", code: -1)) }
        
        switch error.code {
        case LAError.biometryNotAvailable.rawValue:
            return .biometryNotAvailable
        case LAError.biometryNotEnrolled.rawValue:
            return .biometryNotEnrolled
        case LAError.biometryLockout.rawValue:
            return .biometryLockout
        case LAError.userCancel.rawValue:
            return .userCancel
        case LAError.userFallback.rawValue:
            return .userFallback
        case LAError.systemCancel.rawValue:
            return .systemCancel
        default:
            return .unknown(error)
        }
    }
