    private func attemptBiometricLoginIfAvailable() {
        guard biometricAuth.isBiometricAvailable,
              biometricAuth.hasSavedBiometricSession else {
            return
        }
        
        performBiometricLogin()
    }
    
    private func performBiometricLogin() {
        setLoading(true)
        showStatus("", isError: false)
        
        biometricAuth.authenticateWithBiometrics { [weak self] result in
            guard let self = self else { return }
            self.setLoading(false)
            
            switch result {
            case .success(let sessionToken):
                if self.sessionManager.validateToken(sessionToken) {
                    self.sessionManager.setAuthenticated(withToken: sessionToken)
                    self.showStatus("Authentication successful!", isError: false)
                    self.statusLabel.textColor = .systemGreen
                    
                    DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
                        self.navigateToMainApp()
                    }
                } else {
                    self.showStatus("Session expired. Please sign in with your password.", isError: true)
                    self.biometricAuth.disableBiometricLogin()
                    self.biometricButton.isHidden = true
                }
                
            case .failure(let error):
                self.handleBiometricError(error)
            }
        }
    }
    
    private func handleBiometricError(_ error: BiometricAuthManager.AuthError) {
        switch error {
        case .userCancel:
            // User cancelled - do nothing, let them use password
            break
            
        case .userFallback:
            // User wants to enter password
            emailTextField.becomeFirstResponder()
            
        case .biometryLockout:
            showBiometricLockoutAlert()
            
        case .biometryNotAvailable, .biometryNotEnrolled:
            showStatus(error.localizedDescription, isError: true)
            biometricButton.isHidden = true
            
        case .noSessionStored:
            showStatus("Please sign in with your password first to enable \(biometricAuth.biometricDisplayName).", isError: true)
            biometricButton.isHidden = true
            
        case .systemCancel:
            // System cancelled - can retry
            break
            
        case .keychainError, .unknown:
            showRetryAlert(error: error)
        }
    }
    
    private func performPasswordLogin(email: String, password: String) {
        setLoading(true)
        showStatus("", isError: false)
        
        // Simulate network request
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) { [weak self] in
            guard let self = self else { return }
            self.setLoading(false)
            
            // In production, this would be your actual API call
            // Simulating successful login with a session token
            let simulatedToken = "session_\(UUID().uuidString)"
            
            // Validate credentials (replace with real validation)
            guard email.contains("@") && password.count >= 4 else {
                self.showStatus("Invalid email or password. Please try again.", isError: true)
                self.shakeFields()
                return
            }
            
            // Store session token
            do {
                try KeychainManager.shared.storeSessionToken(simulatedToken)
            } catch {
                self.showStatus("Failed to save session securely.", isError: true)
                return
            }
            
            self.sessionManager.setAuthenticated(withToken: simulatedToken)
            
            // Offer biometric enrollment if available and not already set up
            if self.biometricAuth.isBiometricAvailable {
                self.offerBiometricEnrollment(token: simulatedToken)
            } else {
                self.navigateToMainApp()
            }
        }
    }
    
