        alert.addAction(UIAlertAction(title: "Use Password", style: .default) { [weak self] _ in
            self?.emailTextField.becomeFirstResponder()
        })
        
        present(alert, animated: true)
    }
    
    private func showRetryAlert(error: BiometricAuthManager.AuthError) {
        let alert = UIAlertController(
            title: "Authentication Failed",
            message: error.localizedDescription,
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Try Again", style: .default) { [weak self] _ in
            self?.performBiometricLogin()
        })
        
        alert.addAction(UIAlertAction(title: "Use Password", style: .cancel) { [weak self] _ in
            self?.emailTextField.becomeFirstResponder()
        })
        
        present(alert, animated: true)
    }
    
    // MARK: - UI Helpers
    
    private func setLoading(_ loading: Bool) {
        if loading {
            activityIndicator.startAnimating()
            loginButton.isEnabled = false
            biometricButton.isEnabled = false
            loginButton.alpha = 0.6
        } else {
            activityIndicator.stopAnimating()
            loginButton.isEnabled = true
            biometricButton.isEnabled = true
            loginButton.alpha = 1.0
        }
    }
    
    private func showStatus(_ message: String, isError: Bool) {
        statusLabel.text = message
        statusLabel.textColor = isError ? .systemRed : .label
    }
    
    private func shakeFields() {
        let animation = CAKeyframeAnimation(keyPath: "transform.translation.x")
        animation.timingFunction = CAMediaTimingFunction(name: .linear)
        animation.duration = 0.5
        animation.values = [-10, 10, -8, 8, -5, 5, -2, 2, 0]
        
        emailTextField.layer.add(animation, forKey: "shake")
        passwordTextField.layer.add(animation, forKey: "shake")
    }
    
    // MARK: - Navigation
    
    private func navigateToMainApp() {
        let mainVC = MainAppViewController()
        mainVC.modalPresentationStyle = .fullScreen
        mainVC.modalTransitionStyle = .crossDissolve
        
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let window = windowScene.windows.first {
            UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve) {
                window.rootViewController = UINavigationController(rootViewController: mainVC)
            }
        } else {
            present(mainVC, animated: true)
        }
    }
}

// MARK: - UITextFieldDelegate

extension LoginViewController: UITextFieldDelegate {
    func textFieldShouldReturn(_ textField: UITextField) -> Bool {
        if textField == emailTextField {
            passwordTextField.becomeFirstResponder()
        } else if textField == passwordTextField {
            passwordTextField.resignFirstResponder()
            loginButtonTapped()
        }
        return true
    }
}

// MARK: - Main App View Controller (Post-Login)

final class MainAppViewController: UIViewController {
    
    private let sessionManager = SessionManager.shared
    private let biometricAuth = BiometricAuthManager.shared
    
    private let welcomeLabel = UILabel()
    private let sessionInfoLabel = UILabel()
    private let biometricStatusLabel = UILabel()
    private let toggleBiometricButton = UIButton(type: .system)
    private let logoutButton = UIButton(type: .system)
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Home"
        setupUI()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        
        welcomeLabel.text = "🎉 You're Authenticated!"
        welcomeLabel.font = .systemFont(ofSize: 24, weight: .bold)
        welcomeLabel.textAlignment = .center
        
        let tokenPreview: String
        if let token = sessionManager.currentSessionToken {
            let prefix = String(token.prefix(20))
            tokenPreview = "\(prefix)..."
        } else {
            tokenPreview = "N/A"
        }
        sessionInfoLabel.text = "Session: \(tokenPreview)"
        sessionInfoLabel.font = .systemFont(ofSize: 12, weight: .regular)
        sessionInfoLabel.textColor = .secondaryLabel
        sessionInfoLabel.textAlignment = .center
        sessionInfoLabel.numberOfLines = 0
        
        let biometricEnabled = biometricAuth.hasSavedBiometricSession
        biometricStatusLabel.text = "\(biometricAuth.biometricDisplayName): \(biometricEnabled ? "Enabled ✅" : "Disabled ❌")"
        biometricStatusLabel.font = .systemFont(ofSize: 16, weight: .medium)
        biometricStatusLabel.textAlignment = .center
        
        var toggleConfig = UIButton.Configuration.bordered()
        toggleConfig.title = biometricEnabled ? "Disable \(biometricAuth.biometricDisplayName)" : "Enable \(biometricAuth.biometricDisplayName)"
        toggleConfig.image = UIImage(systemName: biometricAuth.biometricIconName)
        toggleConfig.imagePadding = 8
        toggleBiometricButton.configuration = toggleConfig
        toggleBiometricButton.isHidden = !biometricAuth.isBiometricAvailable
        toggleBiometricButton.addTarget(self, action: #selector(toggleBiometric), for: .touchUpInside)
        
        var logoutConfig = UIButton.Configuration.filled()
        logoutConfig.title = "Sign Out"
        logoutConfig.baseBackgroundColor = .systemRed
        logoutConfig.cornerStyle = .large
        logoutButton.configuration = logoutConfig
        logoutButton.addTarget(self, action: #selector(logoutTapped), for: .touchUpInside)
        
        let stackView = UIStackView(arrangedSubviews: [
            welcomeLabel,
            sessionInfoLabel,
            createSpacer(height: 30),
            biometricStatusLabel,
            toggleBiometricButton,
            createSpacer(height: 40),
            logoutButton
        ])
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.alignment = .fill
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            logoutButton.heightAnchor.constraint(equalToConstant: 50)
        ])
    }
    
    private func createSpacer(height: CGFloat) -> UIView {
        let spacer = UIView()
        spacer.translatesAutoresizingMaskIntoConstraints = false
        spacer.heightAnchor.constraint(equalToConstant: height).isActive = true
        return spacer
    }
    
    @objc private func toggleBiometric() {
        if biometricAuth.hasSavedBiometricSession {
            let alert = UIAlertController(
                title: "Disable \(biometricAuth.biometricDisplayName)?",
                message: "You will need to enter your password next time you sign in.",
                preferredStyle: .alert
            )
            alert.addAction(UIAlertAction(title: "Disable", style: .destructive) { [weak self] _ in
                self?.biometricAuth.disableBiometricLogin()
                self?.refreshUI()
            })
            alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
            present(alert, animated: true)
        } else {
            guard let token = sessionManager.currentSessionToken else { return }
            biometricAuth.enableBiometricLogin(withSessionToken: token) { [weak self] result in
                DispatchQueue.main.async {
                    switch result {
                    case .success:
                        self?.refreshUI()
                        let alert = UIAlertController(
                            title: "Success",
                            message: "\(self?.biometricAuth.biometricDisplayName ?? "Biometric") has been enabled.",
                            preferredStyle: .alert
                        )
                        alert.addAction(UIAlertAction(title: "OK", style: .default))
                        self?.present(alert, animated: true)
                    case .failure(let error):
                        let alert = UIAlertController(
                            title: "Error",
                            message: error.localizedDescription,
                            preferredStyle: .alert
                        )
                        alert.addAction(UIAlertAction(title: "OK", style: .default))
                        self?.present(alert, animated: true)
                    }
                }
            }
        }
    }
    
    private func refreshUI() {
        let biometricEnabled = biometricAuth.hasSavedBiometricSession
        biometricStatusLabel.text = "\(biometricAuth.biometricDisplayName): \(biometricEnabled ? "Enabled ✅" : "Disabled ❌")"
        
        var toggleConfig = UIButton.Configuration.bordered()
        toggleConfig.title = biometricEnabled ? "Disable \(biometricAuth.biometricDisplayName)" : "Enable \(biometricAuth.biometricDisplayName)"
        toggleConfig.image = UIImage(systemName: biometricAuth.biometricIconName)
        toggleConfig.imagePadding = 8
        toggleBiometricButton.configuration = toggleConfig
    }
    
    @objc private func logoutTapped() {
        let alert = UIAlertController(
            title: "Sign Out",
            message: "Do you want to keep \(biometricAuth.biometricDisplayName) enabled for next sign in?",
            preferredStyle: .actionSheet
        )
        
        alert.addAction(UIAlertAction(title: "Sign Out (Keep \(biometricAuth.biometricDisplayName))", style: .default) { [weak self] _ in
            self?.sessionManager.logout()
            self?.navigateToLogin()
        })
        
        alert.addAction(UIAlertAction(title: "Sign Out & Remove All Data", style: .destructive) { [weak self] _ in
            self?.sessionManager.fullLogout()
            self?.navigateToLogin()
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    private func navigateToLogin() {
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let window = windowScene.windows.first {
            UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve) {
                window.rootViewController = LoginViewController()
            }
        }
    }
}

// MARK: - App Delegate / Scene Delegate Integration

final class AppFlowController {
    
    static let shared = AppFlowController()
    private let biometricAuth = BiometricAuthManager.shared
    private let sessionManager = SessionManager.shared
    
    private init() {}
    
    func determineInitialViewController() -> UIViewController {
        // If there's a biometric-protected session available, show login
        // (which will auto-trigger biometric auth)
        // Otherwise show login for password entry
        return LoginViewController()
    }
}

// MARK: - SceneDelegate

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        let window = UIWindow(windowScene: windowScene)
        window.rootViewController = AppFlowController.shared.determineInitialViewController()
        window.makeKeyAndVisible()
        self.window = window
    }
    
    func sceneDidBecomeActive(_ scene: UIScene) {
        // Optionally re-validate session when app becomes active
    }
    
    func sceneWillResignActive(_ scene: UIScene) {
        // Optionally add a privacy screen overlay
    }
}